arguments.command:
cd ~/.openclaw && python3 << 'PYEOF'
import json

with open('openclaw.json', 'r') as f:
    config = json.load(f)

# Set up Discord accounts for each sister
discord = config.setdefault('channels', {}).setdefault('discord', {})

# Keep existing default account settings
discord['enabled'] = True
discord['groupPolicy'] = 'allowlist'

# Set up accounts for each bot
discord['accounts'] = {
    'default': {
        'token': '[REDACTED]'  # SAI Army (Prime)
    },
    'forge': {
        'token': '[REDACTED]'
    },
    'scholar': {
        'token': '[REDACTED]'
    },
    'sevenlevers': {
        'token': '[REDACTED]'
    },
    'recovery': {
        'token': '[REDACTED]'
    }
}

# Guild config for all accounts
guild_config = {
    'requireMention': False,
    'users': ['1476700546231697469']  # Aiko's user ID
}

discord['guilds'] = {
    '1476702984954970313': guild_config
}

# Set up bindings to route each Discord bot to the correct agent
bindings = config.setdefault('bindings', [])

# Remove any existing Discord bindings
bindings = [b for b in bindings if b.get('match', {}).get('channel') != 'discord']

# Add Discord bindings for each sister
discord_bindings = [
    {'agentId': 'main', 'match': {'channel': 'discord', 'accountId': 'default'}},
    {'agentId': 'forge', 'match': {'channel': 'discord', 'accountId': 'forge'}},
    {'agentId': 'scholar', 'match': {'channel': 'discord', 'accountId': 'scholar'}},
    {'agentId': 'sevenlevers', 'match': {'channel': 'discord', 'accountId': 'sevenlevers'}},
    {'agentId': 'recovery', 'match': {'channel': 'discord', 'accountId': 'recovery'}}
]

bindings.extend(discord_bindings)
config['bindings'] = bindings

# Remove top-level token (now in accounts)
if 'token' in discord:
    del discord['token']

with open('openclaw.json', 'w') as f:
    json.dump(config, f, indent=2)

print("✅ Discord config updated with 5 sister accounts!")
print("Accounts: default (Prime), forge, scholar, sevenlevers, recovery")
PYEOF

